+export function normalizeClawHubSiteOrigin(value?: string | null) {
+  if (!value) return null
+  try {
+    const url = new URL(value)
+    if (LEGACY_CLAWDHUB_HOSTS.has(url.hostname.toLowerCase())) {
+      return DEFAULT_CLAWHUB_SITE_URL
+    }
+    return url.origin
+  } catch {
+    return null
+  }
+}

